mapper.select:
		SELECT mgr_seq, company_nm, evt_typ_cd, share_url

  		FROM xeus.mt_evet_relay



                AND mgr_seq = #{mgrSeq}::numeric



                AND company_nm = #{companyNm}



                AND evt_typ_cd = #{evtTypCd}



                AND share_url = #{shareUrl}






				${sortCol} ${sortTyp}



				mgr_seq asc




			LIMIT ${limit} OFFSET ${offset}

SELECT mgr_no, org_mgr_no, site_mgr_no, inst_dat, fcl_gbn_cd, atchd_fcl_nm,
       maker_nm, prdt_spec, rmark

       , (SELECT img.file_nm FROM xeus.asset_image AS img WHERE ref_mgr_no = mgr_no LIMIT 1)
       , (SELECT img.mgr_seq FROM xeus.asset_image AS img WHERE ref_mgr_no = mgr_no LIMIT 1)

FROM xeus.asset_acsry



        AND mgr_no = #{mgrNo}



        AND org_mgr_no = #{orgMgrNo}



        AND site_mgr_no = #{siteMgrNo}



        AND inst_dat = #{instDat}



        AND fcl_gbn_cd = #{fclGbnCd}



        AND atchd_fcl_nm like '%'||#{atchdFclNm}||'%'



        AND maker_nm = #{makerNm}



        AND prdt_spec = #{prdtSpec}



        AND rmark = #{rmark}

		SELECT count(*)

        FROM xeus.asset_acsry



                AND mgr_no = #{mgrNo}



                AND org_mgr_no = #{orgMgrNo}



                AND site_mgr_no = #{siteMgrNo}



                AND inst_dat = #{instDat}



                AND fcl_gbn_cd = #{fclGbnCd}



                AND atchd_fcl_nm like '%'||#{atchdFclNm}||'%'



                AND maker_nm = #{makerNm}



                AND prdt_spec = #{prdtSpec}



                AND rmark = #{rmark}

mapper.insert:
INSERT INTO xeus.mt_evet_relay_log(
	company_nm, evt_typ_cd, share_url, json, success, res_val
) VALUES (
	#{companyNm}, #{evtTypCd}, #{shareUrl}, #{json}, #{success}, #{resVal}
);

mapper.update:
		UPDATE xeus.asset_acsry

		SET
            mgr_no = #{mgrNo}


                , org_mgr_no = #{orgMgrNo}



                , site_mgr_no = #{siteMgrNo}



                , inst_dat = #{instDat}



                , fcl_gbn_cd = #{fclGbnCd}



                , atchd_fcl_nm = #{atchdFclNm}



                , maker_nm = #{makerNm}



                , prdt_spec = #{prdtSpec}



                , rmark = #{rmark}


		WHERE mgr_no = #{mgrNo}
